export const signUp = async (req: Request, res: Response) => {
  try {
    const user = await UserService.createUser(req.body);

    return sendSuccess(res, 201, "User registered successfully", user);
  } catch (error) {
    return sendError(res, 500, "Internal Server Error", error);
  }
};

export const login = async (req: Request, res: Response) => {
  try {
    const { email, password } = req.body;

    const user = await UserService.loginValidator(email, password);

    if (!user) {
      return sendError(res, 401, "Invalid email or password");
    }

    const { accessToken, refresToken } = signToken(user);

    res.cookie("refreshToken", refresToken, {
      httpOnly: true,
      sameSite: "lax",
      secure: false,
    });

    return sendSuccess(res, 200, "Login successful", {
      token: accessToken,
      user: {
        id: user.id,
        name: user.name,
        email: user.email,
        role: user.role,
        created_at: user.created_at,
        updated_at: user.updated_at,
      },
    });
  } catch (error) {
    return sendError(res, 500, "Internal Server Error", error);
  }
};

export const updateIssue = async (req: Request, res: Response) => {
  try {
    const id = Number(req.params.id);

    const issue = await IssueService.getIssueById(id);

    if (!issue) {
      return sendError(res, 404, "Issue not found");
    }

    
    if (req.user.role === "contributor" && issue.reporter_id !== req.user.id) {
      return sendError(res, 403, "You can only update your own issues");
    }

    const { title, description, type } = req.body;

    const updated = await IssueService.updateIssue(
      id,
      title,
      description,
      type,
    );

    return sendSuccess(res, 200, "Issue updated successfully", updated);
  } catch (error) {
    return sendError(res, 500, "Internal Server Error", error);
  }
};